const placeholder = (id: string, caption: string, dpd: number, dir_: number, eod: number, acc_p: number, acc_u: number): Analysis => ({
  id,
  caption,
  panels: {
    dpd:      { value: dpd, history: [{ step: 0, value: 0.198 }, { step: 1, value: dpd }] },
    dir:      { value: dir_, history: [{ step: 0, value: 0.355 }, { step: 1, value: dir_ }] },
    eod:      { value: eod, history: [{ step: 0, value: 0.071 }, { step: 1, value: eod }] },
    accuracy: { privileged: acc_p, unprivileged: acc_u, history: [
      { step: 0, value: 0.847 }, { step: 1, value: (acc_p + acc_u) / 2 },
    ] },
    flags: [],
  },
})

